\textit{Source: Sawin, Â§1, Definition (conical).}
  A closed subset, or algebraic cycle, on a vector bundle is \emph{conical} if it
  is invariant under the $\bG_m$-action by dilation of vectors.

\textit{Source: Sawin, Â§2, Definition circ-forward.}
  If $f$ is proper, $f_\circ C$ is the pushforward from $X\times_Y T^*Y$ to
  $T^*Y$ of $df^{-1}(C)$.

\textit{Source: Sawin, Â§2, Definition (Saito 3.5(2)).}
  A pair $h:W\to X$, $f:W\to Y$ is \emph{$C$-transversal} if $h$ is
  $C$-transversal and $f$ is $h^\circ C$-transversal.

\textit{Source: Sawin, Â§3, Lemma multiplicity-polar.}
  Definition~\ref{def:sawin_polar_multiplicity} and
  Definition~\ref{def:sawin_polar_multiplicity_2} agree.

\textit{Source: Sawin, Â§4, Lemma final-nearby-formula.}
  With $\overline X$, $p$, $q$ a general pencil of conics, $\overline x=p^{-1}(x)$,
  $y=q(\overline x)$, and $i:q^{-1}(y)\hookrightarrow\overline X$:
  (1) $\CCyc(\RPsi_q p^*K)=i^!p^!\CCyc'(K)$;
  (2) $\RPhi_q p^*K$ is supported at $x$;
  (3) $-\dimtot(\RPhi_q p^*K)_x$ equals the multiplicity of the cotangent space at
  $x$ in $\CCyc(K)$;
  (4) if $K$ is perverse, $(\RPhi_q p^*K)_x$ is supported in degree $-1$.

\textit{Source: Sawin, Â§5, Lemma ts-smooth-cc.}
  $\CCyc(\underline A_{a,b*}\bQ_\ell[2g-a-b]) = \sum_{0\le w_1+w_2<g}
  m_{w_1,w_2,a,b}\,pr_{w_1,w_2*}[Z_{w_1,w_2}] + m_{a,b}[J]$, where
  $m_{w_1,w_2,a,b}$ is the coefficient of $v_1^{g-a}v_2^{g-b}$ in
  \[ (v_1+v_2+v_1^2v_2+v_1v_2^2)^{w_1}(v_1v_2)^{w_2}
     (1+v_1^2+2v_1v_2+v_2^2+v_1^2v_2^2)^{g-1-w_1-w_2}, \]
  and $|m_{a,b}|\le 8^g$.

\textit{Source: Sawin, Â§5, Lemma ts-decomposition.}
  For $0\le n\le g$, $\pi^n_*\bQ_\ell = \bigoplus_{r=0}^{n/2}
  i^{n+2r}_*\bQ_\ell[-2r](-r)$, where $i^m:\Theta_m\hookrightarrow J$.  (Obtained
  in the proofs of IY Lemma 2.9 / TS Lemma 3.1.)

\textit{Source: Sawin, Â§5, Lemma ts-singular-cc.}
  $\CCyc(\Sigma^{a,b}_*\bQ_\ell[2g-a-b]) = \sum_{0\le w_1+w_2<g}
  m'_{w_1,w_2,a,b}\,pr_{w_1,w_2*}[Z_{w_1,w_2}] + m'_{a,b}[J]$, where
  $m'_{w_1,w_2,a,b}$ is the coefficient of $v_1^{g-a}v_2^{g-b}$ in
  $(1-v_1^{-2})(1-v_2^{-2})$ times the generating function of
  Lemma~\ref{lem:sawin_ts_smooth_cc}, and $|m'_{a,b}|\le 4\cdot 8^g$.

\textit{Source: Sawin, Â§5, Lemma global-polar-bound.}
  For $x\in J$, $\sum_{i=0}^{g-1}\gamma^i_{\CCyc(\Sigma^{a,b}_*\bQ_\ell[2g-a-b])}(x)
  \le 28^g/16$.

\textit{Source: Tsimerman appendix, Lemma.}
  For $\ell_j$ the class of a $j$-dimensional linear subspace of $\PP^k$,
  $\phi_{k*}\psi_k^*\ell_j = r^{k-j}[\Theta_j]$ in $\CHow^*(J^{(k)})$.

\textit{Source: Tsimerman appendix, Theorem appendix.}
  Let $V\subseteq J^{(g)}$ be a subvariety of codimension $j<g$.  Then the
  multiplicity of $V$ at any $v\in V(k)$ is at most $r^{g-1-j}([V],[\Theta_j])$.
